    string name;
    int age;

    Student(string n, int a) // constructor — same name as the class, no return type
    {
        name = n;
        age = a;
    }
};

#include <iostream>
#include <string>

using namespace std;

class Student
{
public:
    string name;
    int age;

    Student(string n, int a)
    {
        name = n;
        age = a;
    }

    void display()
    {
        cout << name << ", age " << age;
    }
};

int main()
{
    Student s1("Aman", 20);

    s1.display();

    return 0;
}

class Student
{
public:
    string name;
    int age;

    Student() // default constructor — takes no parameters
    {
        name = "Unknown";
        age = 0;
    }
};

Student s1; // calls the default constructor automatically

class Student
{
public:
    string name;
    int age;

    Student() // no-argument version
    {
        name = "Unknown";
        age = 0;
    }

    Student(string n, int a) // two-argument version
    {
        name = n;
        age = a;
    }
};

Student s1;               // uses the no-argument constructor
Student s2("Priya", 22);  // uses the two-argument constructor

Student(string n, int a) : name(n), age(a) // initializer list
{
}

